import React from "react"
import { FormattedMessage, injectIntl } from "gatsby-plugin-intl"
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome"
import SEO from "../components/seo";
import AlbumImg from "../images/Reggea_Bass.jpg"

const Contact = ({intl}) => (
    <>
        <SEO title="Contact"/>
        <div className="pb-3">
            <h3>Contact</h3>
            <p>
                <a href="mailto:jens@1ness.de?subject=Booking-Anfrage">
                    <FontAwesomeIcon icon="envelope"/> <FormattedMessage id="book"/>
                </a>
            </p>
            <img src={AlbumImg} className="img-fluid" width="300" alt="Reggae Bass"/>
        </div>
    </>
);

export default injectIntl(Contact)